// core/tree/engine/TreeSelection.multiple.ts

import type { TreeNode } from '../models/TreeNode';

export function toggleMultipleSelection(
  prev: Record<string, boolean> | null | undefined,
  node: TreeNode,
  metaKeySelection?: boolean
): Record<string, boolean> {
  const key = node.key!;
  const next = { ...(prev ?? {}) };

  const exists = !!next[key];

  // RN / mobile-friendly behavior:
  // always accumulate selection
  if (exists) {
    delete next[key];
  } else {
    next[key] = true;
  }

  return next;
}
